CREATE TABLE IF NOT EXISTS EXTERNAL_SERVICES (
    ID UUID PRIMARY KEY,
    NAME VARCHAR(255) NOT NULL,
    URL TEXT NOT NULL,
    PROMPT TEXT,
    TIMEOUT_MS INTEGER DEFAULT 5000,
    RETRY_COUNT INTEGER DEFAULT 3,
    CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS EXTERNAL_SERVICE_HEADERS (
    ID INT AUTO_INCREMENT PRIMARY KEY,
    SERVICE_ID UUID REFERENCES EXTERNAL_SERVICES(ID) ON DELETE CASCADE,
    HEADER_KEY VARCHAR(100) NOT NULL,
    HEADER_VALUE TEXT NOT NULL,
    CATEGORY VARCHAR(20) DEFAULT 'STANDARD' CHECK (CATEGORY IN ('STANDARD', 'SECURITY')),

    CONSTRAINT fk_service
        FOREIGN KEY(SERVICE_ID) 
        REFERENCES EXTERNAL_SERVICES(ID) 
        ON DELETE CASCADE   
);
